LOGIN_HTML = '<!DOCTYPE html>\n<html>\n<head>\n<meta charset="UTF-8">\n<link href="https://fonts.googleapis.com/css2?family=Rajdhani:wght@500;600;700&family=Exo+2:wght@300;400;600;800&display=swap" rel="stylesheet">\n<style>\n  *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }\n  :root {\n    --bg-deep: #020b18;\n    --bg-field: #07192e;\n    --border-glow: #00c8ff;\n    --border-dim: #0a2a42;\n    --accent-cyan: #00d4ff;\n    --accent-blue: #0077ff;\n    --accent-hot: #00ffcc;\n    --text-primary: #e8f4ff;\n    --text-muted: #4a7a9b;\n  }\n  body {\n    min-height: 100vh;\n    display: flex;\n    align-items: center;\n    justify-content: center;\n    background: var(--bg-deep);\n    font-family: \'Exo 2\', sans-serif;\n    overflow: hidden;\n    position: relative;\n  }\n\n  #bg-canvas { position: fixed; inset: 0; z-index: 0; }\n\n  .grid-bg {\n    position: fixed; inset: 0; z-index: 1;\n    background-image:\n      linear-gradient(rgba(0,200,255,0.025) 1px, transparent 1px),\n      linear-gradient(90deg, rgba(0,200,255,0.025) 1px, transparent 1px);\n    background-size: 50px 50px;\n    animation: gridMove 25s linear infinite;\n  }\n  @keyframes gridMove { 0%{transform:translateY(0)} 100%{transform:translateY(50px)} }\n\n  .side-elements { position: fixed; inset: 0; z-index: 2; pointer-events: none; }\n\n  .hex {\n    position: absolute;\n    border: 1px solid rgba(0,200,255,0.15);\n    clip-path: polygon(50% 0%,100% 25%,100% 75%,50% 100%,0% 75%,0% 25%);\n    animation: hexFloat linear infinite;\n  }\n  @keyframes hexFloat {\n    0%   { transform: translateY(0) rotate(0deg);   opacity: 0; }\n    10%  { opacity: 1; }\n    90%  { opacity: 1; }\n    100% { transform: translateY(-110vh) rotate(360deg); opacity: 0; }\n  }\n\n  .pulse-ring {\n    position: absolute;\n    border-radius: 50%;\n    border: 1px solid rgba(0,119,255,0.2);\n    animation: ringPulse ease-out infinite;\n  }\n  @keyframes ringPulse {\n    0%   { transform: scale(0.6); opacity: 0.8; }\n    100% { transform: scale(2.2); opacity: 0; }\n  }\n\n  .h-line {\n    position: absolute; left: 0; right: 0; height: 1px;\n    background: linear-gradient(90deg, transparent 0%, rgba(0,200,255,0.3) 20%, rgba(0,200,255,0.6) 50%, rgba(0,200,255,0.3) 80%, transparent 100%);\n    animation: hLineScan linear infinite;\n  }\n  @keyframes hLineScan {\n    0%   { top: 110%; opacity: 0; }\n    5%   { opacity: 1; }\n    95%  { opacity: 1; }\n    100% { top: -10%; opacity: 0; }\n  }\n\n  .data-bar { position: absolute; top: 0; width: 1px; height: 100%; overflow: hidden; }\n\n  .code-stream {\n    position: absolute; top: 0;\n    font-family: \'Rajdhani\', monospace; font-size: 11px;\n    letter-spacing: 1px; line-height: 1.9;\n    color: rgba(0,200,255,0.18);\n    animation: streamFall linear infinite;\n    white-space: nowrap; user-select: none;\n  }\n  @keyframes streamFall {\n    0%   { transform: translateY(-100%); opacity: 0; }\n    5%   { opacity: 1; }\n    80%  { opacity: 1; }\n    100% { transform: translateY(100vh); opacity: 0; }\n  }\n\n  .orb { position: fixed; border-radius: 50%; filter: blur(70px); pointer-events: none; animation: floatOrb ease-in-out infinite; z-index: 1; }\n  .orb-1 { width:300px;height:300px;background:rgba(0,119,255,0.1);  top:5%;   left:-8%; animation-duration:9s;  animation-delay:0s; }\n  .orb-2 { width:250px;height:250px;background:rgba(0,212,255,0.08); bottom:8%;right:-6%;animation-duration:11s; animation-delay:-5s;}\n  .orb-3 { width:180px;height:180px;background:rgba(0,255,204,0.06); top:55%;  left:2%;  animation-duration:7s;  animation-delay:-3s;}\n  .orb-4 { width:200px;height:200px;background:rgba(0,119,255,0.07); top:20%;  right:2%; animation-duration:13s; animation-delay:-7s;}\n  @keyframes floatOrb {\n    0%,100% { transform:translateY(0) scale(1); }\n    50%      { transform:translateY(-35px) scale(1.08); }\n  }\n\n  .container { position: relative; z-index: 10; width: 420px; animation: fadeIn 0.8s ease both; }\n  @keyframes fadeIn { from{opacity:0;transform:translateY(24px)} to{opacity:1;transform:translateY(0)} }\n\n  .panel {\n    background: linear-gradient(160deg, rgba(4,15,30,0.97) 0%, rgba(2,11,24,0.99) 100%);\n    border: 1px solid var(--border-dim); border-radius: 16px;\n    padding: 44px 40px 36px; position: relative;\n    box-shadow: 0 0 0 1px rgba(0,200,255,0.05), 0 30px 80px rgba(0,0,0,0.7), 0 0 60px rgba(0,119,255,0.07), inset 0 1px 0 rgba(0,200,255,0.08);\n    overflow: hidden;\n  }\n  .panel::before {\n    content:\'\'; position:absolute; top:0; left:10%; right:10%; height:2px;\n    background:linear-gradient(90deg,transparent,var(--accent-cyan),var(--accent-blue),var(--accent-cyan),transparent);\n    animation:linePulse 3s ease-in-out infinite;\n  }\n  @keyframes linePulse { 0%,100%{opacity:0.6} 50%{opacity:1;box-shadow:0 0 12px var(--accent-cyan)} }\n\n  .scan-line { position:absolute;left:0;right:0;height:1px;background:linear-gradient(90deg,transparent,rgba(0,200,255,0.4),transparent);animation:scan 5s linear infinite;pointer-events:none; }\n  @keyframes scan { 0%{top:0;opacity:0} 10%{opacity:1} 90%{opacity:1} 100%{top:100%;opacity:0} }\n\n  .corner{ position:absolute; width:16px; height:16px; }\n  .corner-tl{ top:8px;left:8px;border-top:2px solid var(--accent-cyan);border-left:2px solid var(--accent-cyan); }\n  .corner-tr{ top:8px;right:8px;border-top:2px solid var(--accent-cyan);border-right:2px solid var(--accent-cyan); }\n  .corner-bl{ bottom:8px;left:8px;border-bottom:2px solid var(--border-glow);border-left:2px solid var(--border-glow);opacity:0.4; }\n  .corner-br{ bottom:8px;right:8px;border-bottom:2px solid var(--border-glow);border-right:2px solid var(--border-glow);opacity:0.4; }\n\n  .logo-area{ text-align:center; margin-bottom:36px; }\n  .logo-icon{\n    width:56px;height:56px;margin:0 auto 16px;\n    background:linear-gradient(135deg,var(--accent-blue),var(--accent-cyan));\n    border-radius:14px;display:flex;align-items:center;justify-content:center;\n    font-size:26px;box-shadow:0 0 24px rgba(0,119,255,0.4),0 0 48px rgba(0,119,255,0.15);\n    animation:iconGlow 3s ease-in-out infinite;position:relative;overflow:hidden;\n  }\n  .logo-icon::after{\n    content:\'\';position:absolute;top:-50%;left:-50%;width:200%;height:200%;\n    background:linear-gradient(45deg,transparent 30%,rgba(255,255,255,0.12) 50%,transparent 70%);\n    animation:shine 4s ease-in-out infinite;\n  }\n  @keyframes iconGlow { 0%,100%{box-shadow:0 0 24px rgba(0,119,255,0.4),0 0 48px rgba(0,119,255,0.15)} 50%{box-shadow:0 0 36px rgba(0,200,255,0.6),0 0 60px rgba(0,200,255,0.2)} }\n  @keyframes shine { 0%{transform:translateX(-100%) rotate(45deg)} 30%,100%{transform:translateX(100%) rotate(45deg)} }\n\n  .logo-title{\n    font-family:\'Rajdhani\',sans-serif;font-size:26px;font-weight:700;\n    letter-spacing:4px;text-transform:uppercase;\n    background:linear-gradient(135deg,#ffffff,var(--accent-cyan));\n    -webkit-background-clip:text;-webkit-text-fill-color:transparent;background-clip:text;line-height:1.1;\n  }\n  .logo-sub{ font-size:10px;letter-spacing:6px;color:var(--text-muted);text-transform:uppercase;margin-top:4px; }\n\n  .field-group{ margin-bottom:18px; }\n  label{ display:block;font-size:11px;font-weight:600;letter-spacing:2px;text-transform:uppercase;color:var(--text-muted);margin-bottom:8px; }\n  .field-wrap{ position:relative; }\n  .field-icon{ position:absolute;left:14px;top:50%;transform:translateY(-50%);font-size:15px;opacity:0.5;pointer-events:none;transition:opacity 0.3s; }\n\n  input[type="text"], input[type="password"] {\n    width:100%;padding:13px 14px 13px 42px;\n    background:var(--bg-field);border:1px solid var(--border-dim);border-radius:8px;\n    color:var(--text-primary);font-family:\'Exo 2\',sans-serif;font-size:14px;\n    outline:none;transition:all 0.3s ease;letter-spacing:0.5px;\n  }\n  input::placeholder{ color:#1e3a52;letter-spacing:1px; }\n  input:focus{ border-color:var(--accent-cyan);background:rgba(7,25,46,0.9);box-shadow:0 0 0 3px rgba(0,200,255,0.08),0 0 20px rgba(0,200,255,0.06); }\n\n  .eye-btn{ position:absolute;right:12px;top:50%;transform:translateY(-50%);background:none;border:none;color:var(--text-muted);cursor:pointer;font-size:16px;padding:4px;transition:color 0.2s;line-height:1; }\n  .eye-btn:hover{ color:var(--accent-cyan); }\n\n  .key-badge{\n    position:absolute;left:12px;top:50%;transform:translateY(-50%);\n    background:linear-gradient(90deg,rgba(0,119,255,0.2),rgba(0,200,255,0.2));\n    border:1px solid rgba(0,200,255,0.2);border-radius:4px;\n    padding:2px 7px;font-size:9px;letter-spacing:1.5px;color:var(--accent-cyan);font-weight:700;text-transform:uppercase;white-space:nowrap;\n  }\n  .key-input{ padding-left:56px!important;font-family:\'Rajdhani\',monospace!important;letter-spacing:2px!important;color:rgba(0,200,255,0.7)!important; }\n\n  .save-row{ display:flex;align-items:center;gap:10px;margin:22px 0 28px; }\n  .check-wrap{ position:relative;width:18px;height:18px;flex-shrink:0; }\n  .check-wrap input{ opacity:0;position:absolute;inset:0;cursor:pointer;margin:0; }\n  .checkmark{ position:absolute;inset:0;background:var(--bg-field);border:1px solid var(--border-dim);border-radius:4px;display:flex;align-items:center;justify-content:center;transition:all 0.2s;pointer-events:none; }\n  .check-wrap input:checked ~ .checkmark{ background:linear-gradient(135deg,var(--accent-blue),var(--accent-cyan));border-color:transparent; }\n  .checkmark::after{ content:\'✓\';color:white;font-size:11px;font-weight:800;opacity:0;transform:scale(0.5);transition:all 0.2s; }\n  .check-wrap input:checked ~ .checkmark::after{ opacity:1;transform:scale(1); }\n  .save-label{ font-size:12px;color:var(--text-muted);letter-spacing:0.5px;display:flex;align-items:center;gap:6px; }\n\n  .btn-access{\n    width:100%;padding:15px;\n    background:linear-gradient(135deg,var(--accent-blue) 0%,var(--accent-cyan) 100%);\n    border:none;border-radius:8px;color:#fff;\n    font-family:\'Rajdhani\',sans-serif;font-size:16px;font-weight:700;\n    letter-spacing:4px;text-transform:uppercase;cursor:pointer;\n    position:relative;overflow:hidden;transition:all 0.3s ease;\n    box-shadow:0 4px 24px rgba(0,119,255,0.35);\n  }\n  .btn-access::before{ content:\'\';position:absolute;top:0;left:-100%;width:100%;height:100%;background:linear-gradient(90deg,transparent,rgba(255,255,255,0.15),transparent);transition:left 0.5s ease; }\n  .btn-access:hover{ transform:translateY(-1px);box-shadow:0 8px 32px rgba(0,200,255,0.45); }\n  .btn-access:hover::before{ left:100%; }\n  .btn-access:active{ transform:translateY(0); }\n  .btn-inner{ display:flex;align-items:center;justify-content:center;gap:10px; }\n\n  .footer{ text-align:center;margin-top:24px;display:flex;align-items:center;justify-content:center;gap:8px; }\n  .status-dot{ width:6px;height:6px;border-radius:50%;background:var(--accent-hot);animation:blink 2s ease-in-out infinite;box-shadow:0 0 6px var(--accent-hot); }\n  @keyframes blink{ 0%,100%{opacity:1} 50%{opacity:0.3} }\n  .footer-text{ font-size:10px;letter-spacing:3px;text-transform:uppercase;color:var(--text-muted); }\n</style>\n</head>\n<body>\n\n<canvas id="bg-canvas"></canvas>\n<div class="grid-bg"></div>\n<div class="orb orb-1"></div>\n<div class="orb orb-2"></div>\n<div class="orb orb-3"></div>\n<div class="orb orb-4"></div>\n<div class="side-elements" id="sideElements"></div>\n\n<script>\n// Expande o próprio iframe para tela cheia assim que o DOM carrega\n(function() {\n  try {\n    const f = window.frameElement;\n    if (f) {\n      f.style.cssText = \'position:fixed!important;top:0!important;left:0!important;\' +\n        \'width:100vw!important;height:100vh!important;z-index:999999!important;border:none!important;\';\n    }\n  } catch(e) {}\n})();\n</script>\n\n<div class="container">\n  <div class="panel">\n    <div class="scan-line"></div>\n    <div class="corner corner-tl"></div>\n    <div class="corner corner-tr"></div>\n    <div class="corner corner-bl"></div>\n    <div class="corner corner-br"></div>\n\n    <div class="logo-area">\n      <div class="logo-icon">⚡</div>\n      <div class="logo-title">Hero Juvicks</div>\n      <div class="logo-sub">System</div>\n    </div>\n\n    <div class="field-group">\n      <label>Usuário</label>\n      <div class="field-wrap">\n        <input type="text" id="user" placeholder="Digite seu usuário" autocomplete="off">\n        <span class="field-icon">👤</span>\n      </div>\n    </div>\n\n    <div class="field-group">\n      <label>Senha</label>\n      <div class="field-wrap">\n        <input type="password" id="pwd" placeholder="••••••••">\n        <span class="field-icon">🔒</span>\n        <button class="eye-btn" onclick="togglePwd()" type="button" id="eyeBtn">👁</button>\n      </div>\n    </div>\n\n    <div class="field-group">\n      <label>Chave de Acesso</label>\n      <div class="field-wrap">\n        <input type="text" id="key" class="key-input" placeholder="JUV-XXXX-XXXX" autocomplete="off">\n        <span class="key-badge">KEY</span>\n      </div>\n    </div>\n\n    <div class="save-row">\n      <label class="check-wrap">\n        <input type="checkbox" id="keep" checked>\n        <div class="checkmark"></div>\n      </label>\n      <span class="save-label">🔐 Salvar neste dispositivo</span>\n    </div>\n\n    <button class="btn-access" type="button" onclick="submitLogin()">\n      <div class="btn-inner">\n        <span>🚀</span>\n        <span>ACESSAR</span>\n      </div>\n    </button>\n\n    <div class="footer">\n      <div class="status-dot"></div>\n      <span class="footer-text">Dispositivo: Remoto</span>\n    </div>\n  </div>\n</div>\n\n<script>\n// ── CANVAS partículas ──\nconst canvas = document.getElementById(\'bg-canvas\');\nconst ctx = canvas.getContext(\'2d\');\nlet W, H, particles = [];\n\nfunction resize() { W = canvas.width = window.innerWidth; H = canvas.height = window.innerHeight; }\nresize();\nwindow.addEventListener(\'resize\', () => { resize(); init(); });\n\nfunction rand(a, b) { return Math.random()*(b-a)+a; }\n\nfunction init() {\n  particles = [];\n  const count = Math.floor((W * H) / 14000);\n  for (let i = 0; i < count; i++) {\n    particles.push({ x:rand(0,W), y:rand(0,H), vx:rand(-0.25,0.25), vy:rand(-0.25,0.25), r:rand(1,2.5), alpha:rand(0.2,0.7) });\n  }\n}\ninit();\n\nfunction drawParticles() {\n  ctx.clearRect(0, 0, W, H);\n  for (let i = 0; i < particles.length; i++) {\n    for (let j = i+1; j < particles.length; j++) {\n      const dx = particles[i].x - particles[j].x;\n      const dy = particles[i].y - particles[j].y;\n      const dist = Math.sqrt(dx*dx + dy*dy);\n      if (dist < 130) {\n        ctx.beginPath();\n        ctx.moveTo(particles[i].x, particles[i].y);\n        ctx.lineTo(particles[j].x, particles[j].y);\n        ctx.strokeStyle = `rgba(0,180,255,${0.08*(1-dist/130)})`;\n        ctx.lineWidth = 0.7;\n        ctx.stroke();\n      }\n    }\n  }\n  particles.forEach(p => {\n    ctx.beginPath();\n    ctx.arc(p.x, p.y, p.r, 0, Math.PI*2);\n    ctx.fillStyle = `rgba(0,200,255,${p.alpha})`;\n    ctx.shadowBlur = 6; ctx.shadowColor = \'#00d4ff\';\n    ctx.fill(); ctx.shadowBlur = 0;\n    p.x += p.vx; p.y += p.vy;\n    if (p.x < 0) p.x = W; if (p.x > W) p.x = 0;\n    if (p.y < 0) p.y = H; if (p.y > H) p.y = 0;\n  });\n  requestAnimationFrame(drawParticles);\n}\ndrawParticles();\n\n// ── Elementos laterais ──\nconst sideEl = document.getElementById(\'sideElements\');\nconst codeChars = [\'01\',\'10\',\'JUV\',\'HEX\',\'SYS\',\'001\',\'110\',\'KEY\',\'USR\',\'NET\',\'SEC\',\'AUT\'];\n\nfunction spawnHex() {\n  const hex = document.createElement(\'div\');\n  hex.className = \'hex\';\n  const size = rand(30, 90);\n  const leftSide = Math.random() < 0.5;\n  hex.style.cssText = `width:${size}px;height:${size}px;left:${leftSide?rand(0,30):rand(70,100)}%;bottom:-${size}px;animation-duration:${rand(8,18)}s;animation-delay:${rand(0,3)}s;border-color:rgba(0,${Math.floor(rand(150,255))},255,${rand(0.08,0.2)});background:rgba(0,150,255,${rand(0.01,0.04)});`;\n  sideEl.appendChild(hex);\n  setTimeout(() => hex.remove(), 20000);\n}\n\nfunction spawnHLine() {\n  const line = document.createElement(\'div\');\n  line.className = \'h-line\';\n  const dur = rand(6, 14);\n  line.style.cssText = `animation-duration:${dur}s;`;\n  sideEl.appendChild(line);\n  setTimeout(() => line.remove(), dur*1000+500);\n}\n\nfunction spawnDataBar() {\n  const bar = document.createElement(\'div\');\n  bar.className = \'data-bar\';\n  const dur = rand(3, 8);\n  const leftSide = Math.random() < 0.5;\n  bar.style.cssText = `left:${leftSide?rand(2,28):rand(72,98)}%;`;\n  const inner = document.createElement(\'div\');\n  inner.style.cssText = `position:absolute;width:1px;background:linear-gradient(to bottom,transparent,#00d4ff,#00ffcc,transparent);animation:dataFlow ${dur}s linear forwards;`;\n  bar.appendChild(inner);\n  sideEl.appendChild(bar);\n  setTimeout(() => bar.remove(), dur*1000+500);\n}\n\nfunction spawnCodeStream() {\n  const el = document.createElement(\'div\');\n  el.className = \'code-stream\';\n  const col = Array.from({length:rand(10,20)|0}, () => codeChars[Math.floor(rand(0,codeChars.length))]).join(\'\\n\');\n  el.textContent = col;\n  const leftSide = Math.random() < 0.5;\n  const dur = rand(6, 14);\n  el.style.cssText = `left:${leftSide?rand(0,25):rand(75,98)}%;animation-duration:${dur}s;color:rgba(0,200,255,${rand(0.1,0.25)});`;\n  sideEl.appendChild(el);\n  setTimeout(() => el.remove(), dur*1000+500);\n}\n\nfunction spawnRing() {\n  const ring = document.createElement(\'div\');\n  ring.className = \'pulse-ring\';\n  const size = rand(60, 160);\n  const leftSide = Math.random() < 0.5;\n  ring.style.cssText = `width:${size}px;height:${size}px;left:${leftSide?rand(-5,25):rand(75,105)}%;top:${rand(10,90)}%;animation-duration:${rand(2,5)}s;border-color:rgba(0,${Math.floor(rand(100,220))},255,0.2);`;\n  sideEl.appendChild(ring);\n  setTimeout(() => ring.remove(), 6000);\n}\n\nsetInterval(spawnHex, 1200);\nsetInterval(spawnHLine, 3500);\nsetInterval(spawnDataBar, 900);\nsetInterval(spawnCodeStream, 2200);\nsetInterval(spawnRing, 1800);\nfor(let i=0;i<4;i++){spawnHex();spawnDataBar();}\nfor(let i=0;i<2;i++){spawnCodeStream();spawnRing();}\n\n// ── Inputs ──\nfunction togglePwd() {\n  const p = document.getElementById(\'pwd\');\n  const b = document.getElementById(\'eyeBtn\');\n  if (p.type===\'password\'){p.type=\'text\';b.textContent=\'🙈\';}\n  else{p.type=\'password\';b.textContent=\'👁\';}\n}\n\ndocument.querySelector(\'.key-input\').addEventListener(\'input\', function(e) {\n  // Apenas remove espaços e garante maiúsculas, sem forçar traços\n  let v = e.target.value.toUpperCase().replace(/\\s/g, \'\');\n  e.target.value = v;\n});\n\nfunction submitLogin() {\n  const u = document.getElementById(\'user\').value.trim();\n  const p = document.getElementById(\'pwd\').value.trim();\n  const k = document.getElementById(\'key\').value.trim();\n  if(!u || !p) {\n    alert("Por favor, preencha o Usuário e a Senha.");\n    return;\n  }\n\n  const btnHtml = document.querySelector(\'.btn-access .btn-inner\');\n  if(btnHtml) btnHtml.innerHTML = \'<span>⏳</span><span>CONECTANDO...</span>\';\n\n  // Construímos os parâmetros\n  const params = \'?login_u=\' + encodeURIComponent(u) +\n                 \'&login_p=\' + encodeURIComponent(p) +\n                 \'&login_k=\' + encodeURIComponent(k);\n\n  // Tentamos determinar a URL base do pai de forma segura\n  let baseUrl = "";\n  try {\n    // Tenta acessar o pai (mesma origem)\n    baseUrl = window.parent.location.origin + window.parent.location.pathname;\n  } catch(e) {\n    // Se falhar (CORS/Sandbox), tenta inferir pela URL do iframe (Streamlit convention)\n    // No Streamlit, componentes ficam em /component/nome_do_componente/...\n    const currentPath = window.location.pathname;\n    baseUrl = currentPath.split(\'/component/\')[0] || "/";\n  }\n\n  const loginUrl = baseUrl + params;\n\n  // Estratégia de Redirecionamento em cascata\n  try {\n    // 1. Tentativa padrão no pai\n    window.parent.location.href = loginUrl;\n  } catch(e) {\n    try {\n      // 2. Tentativa no topo (se houver múltiplos aninhamentos)\n      window.top.location.href = loginUrl;\n    } catch(e2) {\n      // 3. Fallback via Link (mais permissivo em sandboxes)\n      const a = document.createElement(\'a\');\n      a.href = loginUrl;\n      a.target = \'_parent\';\n      document.body.appendChild(a);\n      a.click();\n      \n      // 4. Último recurso: redireciona o próprio frame (Streamlit detecta mudança de URL geral)\n      setTimeout(() => {\n        if(window.location.href !== loginUrl) window.location.href = loginUrl;\n      }, 500);\n    }\n  }\n}\n</script>\n</body>\n</html>\n'
